function AreaIcon({ iconKey, size = 56 }) {
  const content = areaIconPaths[iconKey]
  if (!content) return null
  if (typeof content === 'function') return content(size)
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 40 40"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      {content}
    </svg>
  )
}

